export const purchasePackageFirestore = async (userId: string, pkgId: string) => {
  try {
    const pkg = INITIAL_PACKAGES.find(p => p.id === pkgId);
    if (!pkg) throw new Error("Invalid Package Configuration");

    // Fetch potential active package ref outside transaction to know which doc to lock
    const activePkgsQuery = query(collection(db, 'activePackages'), where('userId', '==', userId), where('isActive', '==', true));
    const activePkgsSnap = await getDocs(activePkgsQuery);
    const existingDocRef = activePkgsSnap.empty ? null : activePkgsSnap.docs[0].ref;

    const userRef = doc(db, 'users', userId);

    await runTransaction(db, async (transaction) => {
      // 1. Read User
      const userSnap = await transaction.get(userRef);
      if (!userSnap.exists()) throw new Error("User does not exist!");
      const userData = userSnap.data() as User;

      let cost = pkg.minAmount;
      let isUpgrade = false;
      let currentData: UserPackage | null = null;

      // 2. Read Active Package (if exists) inside transaction for consistency
      if (existingDocRef) {
        const pkgSnap = await transaction.get(existingDocRef);
        if (pkgSnap.exists()) {
          currentData = pkgSnap.data() as UserPackage;

          if (currentData.packageId === pkgId) throw new Error("Plan is already active.");
          if (pkg.minAmount <= currentData.amount) throw new Error("Cannot downgrade to a lower tier.");

          cost = pkg.minAmount - currentData.amount;
          isUpgrade = true;
        }
      }

      // 3. Check Balance
      if (userData.capitalBalance < cost) throw new Error(`Insufficient balance. Required: ${cost.toFixed(2)} USDT`);

      // 4. Perform Updates
      transaction.update(userRef, {
        capitalBalance: increment(-cost)
      });

      if (isUpgrade && existingDocRef && currentData) {
        transaction.update(existingDocRef, {
          packageId: pkg.id,
          amount: pkg.minAmount,
          activatedAt: Date.now(),
          lastPayoutAt: Date.now() // Reset timer on upgrade to prevent exploit
        });

        const txRef = doc(collection(db, 'transactions'));
        transaction.set(txRef, {
          id: txRef.id,
          userId,
          type: TransactionType.PURCHASE,
          amount: cost,
          status: TransactionStatus.COMPLETED,
          timestamp: Date.now(),
          description: `Upgrade to ${pkg.name}`
        });
      } else {
        // New activation
        const activePkgRef = doc(collection(db, 'activePackages'));
        transaction.set(activePkgRef, {
          id: activePkgRef.id,
          packageId: pkg.id,
          amount: pkg.minAmount,
          activatedAt: Date.now(),
          lastPayoutAt: Date.now(), // Initialize timer
          isActive: true,
          totalEarned: 0,
          userId
        });
        const txRef = doc(collection(db, 'transactions'));
        transaction.set(txRef, {
          id: txRef.id,
          userId,
          type: TransactionType.PURCHASE,
          amount: pkg.minAmount, 
          status: TransactionStatus.COMPLETED,
          timestamp: Date.now(),
          description: `Node Activation: ${pkg.name}`
        });
      }
    });
  } catch (err: any) {
    const msg = err?.message || "Transaction failed";
    console.error("Transaction Error:", msg);
    throw new Error(msg);
  }
};

export const processDailyRoiFirestore = async (settings: any) => {
  if (!settings.isRoiEnabled || settings.platformPaused) return;
  const activePkgsQuery = query(collection(db, 'activePackages'), where('isActive', '==', true));
  const activePkgsSnap = await getDocs(activePkgsQuery);
  const now = Date.now();
  const ONE_DAY_MS = 24 * 60 * 60 * 1000;

  for (const docSnap of activePkgsSnap.docs) {
    const ap = docSnap.data() as UserPackage;
    const pkg = INITIAL_PACKAGES.find(p => p.id === ap.packageId);
    if (!pkg) continue;

    const lastPayout = ap.lastPayoutAt || ap.activatedAt;

    // Check if 24 hours have passed since last payout
    if (now - lastPayout < ONE_DAY_MS) continue;

    const dailyPercent = settings.roiOverride || pkg.dailyRoi;
    const earnings = ap.amount * (dailyPercent / 100);

    await runTransaction(db, async (transaction) => {
      const userRef = doc(db, 'users', ap.userId);
      transaction.update(userRef, {
        profitBalance: increment(earnings),
        totalEarned: increment(earnings)
      });
      transaction.update(doc(db, 'activePackages', docSnap.id), {
        totalEarned: increment(earnings),
        lastPayoutAt: now
      });
      const txRef = doc(collection(db, 'transactions'));
      transaction.set(txRef, {
        id: txRef.id,
        userId: ap.userId,
        type: TransactionType.ROI,
        amount: earnings,
        status: TransactionStatus.COMPLETED,
        timestamp: now,
        description: `Daily profit from ${pkg.name}`
      });
    });
  }
};

import React, { useState, useEffect } from 'react';
import { User, Transaction, UserPackage, TransactionType } from '../types.ts';
import { motion } from 'framer-motion';
import { INITIAL_PACKAGES } from '../constants.tsx';

interface DashboardProps {
  user: User;
  transactions: Transaction[];
  activePackages: UserPackage[];
}

const Dashboard: React.FC<DashboardProps> = ({ user, transactions, activePackages }) => {
  const activeStakes = activePackages.filter(p => p.isActive).reduce((sum, p) => sum + p.amount, 0);

  const currentPkg = activePackages.find(p => p.isActive);
  const pkgDetails = currentPkg ? INITIAL_PACKAGES.find(p => p.id === currentPkg.packageId) : null;

  const [timeLeft, setTimeLeft] = useState<string>('');

  useEffect(() => {
    if (!currentPkg) {
      setTimeLeft('');
      return;
    }

    const interval = setInterval(() => {
      const lastPayout = currentPkg.lastPayoutAt || currentPkg.activatedAt;
      const nextPayout = lastPayout + (24 * 60 * 60 * 1000);
      const now = Date.now();
      const diff = nextPayout - now;

      if (diff <= 0) {
        setTimeLeft('Generating...');
      } else {
        const hours = Math.floor(diff / (1000 * 60 * 60));
        const minutes = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
        const seconds = Math.floor((diff % (1000 * 60)) / 1000);
        setTimeLeft(`${hours}h ${minutes}m ${seconds}s`);
      }
    }, 1000);

    return () => clearInterval(interval);
  }, [currentPkg]);

  const stats = [
    { label: 'Total Asset Value', value: user.capitalBalance + user.profitBalance + activeStakes + user.welcomeBonus, type: 'currency', icon: 'fa-vault' },
    { label: 'Wallet Balance', value: user.capitalBalance, type: 'currency', icon: 'fa-wallet' },
    { label: 'Active Staked', value: activeStakes, type: 'currency', icon: 'fa-server' },
    { 
      label: 'Yield Generated', 
      value: user.profitBalance, 
      type: 'currency', 
      icon: 'fa-arrow-trend-up',
      countdown: timeLeft 
    },
    { label: 'Welcome Bonus', value: user.welcomeBonus, type: 'currency', icon: 'fa-gift', highlight: true },
  ];

  const getTxSign = (type: TransactionType) => {
    return (type === TransactionType.WITHDRAWAL || type === TransactionType.PURCHASE) ? '-' : '+';
  };

  const getTxIcon = (type: TransactionType) => {
    if (type === TransactionType.WITHDRAWAL) return 'fa-arrow-up';
    if (type === TransactionType.PURCHASE) return 'fa-cart-shopping';
    return 'fa-arrow-down';
  };

  // Calculate estimated daily earnings if active
  const dailyEarnings = currentPkg && pkgDetails 
    ? (currentPkg.amount * (pkgDetails.dailyRoi / 100)) 
    : 0;

  return (
    <div className="space-y-16 max-w-7xl mx-auto pb-24 lg:pb-0">

      {/* Hero / Node Status Section */}
      <div className="flex flex-col gap-8">
        <div className="flex flex-col gap-2">
            <motion.h1 
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                className="text-6xl lg:text-8xl font-black uppercase tracking-tighter leading-none text-app-text"
            >
            Node Status: <br />
            <span className={pkgDetails ? "text-green-500" : "text-app-muted/50"}>
                {pkgDetails ? 'Operational' : 'Standby'}
            </span>
            </motion.h1>
            <motion.p 
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ delay: 0.2 }}
                className="serif italic text-xl text-app-muted max-w-xl"
            >
            {pkgDetails 
                ? `Running ${pkgDetails.name} protocol. Yield generation active.` 
                : "No active liquidity node detected. Deploy a node to commence yield generation."}
            </motion.p>
        </div>

        {/* Active Node Card - Prominent Display */}
